#include <bits/stdc++.h>
using namespace std;
const int N=5005;
long long x[N],y[N],dp[2][N],n,m;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++) cin>>x[i];
	cin>>m;
	for(int i=1;i<=m;i++)
	{
		cin>>y[i];
	}
	sort(x+1,x+1+n);
	sort(y+1,y+1+m);
	memset(dp,0x3f,sizeof(dp));
	dp[1][1]=abs(x[1]-y[1]);
	for(int i=2;i<=n;i++)
	{
		for(int j=1;j<=i&&j<=m;j++)
		{
			dp[i%2][j]=min(dp[(i+1)%2][j],dp[(i+1)%2][j-1])+abs(x[i]-y[j]);
//            cout<<"a"<<dp[i%2][j]<<" "<<dp[(i+1)%2][j]<<" "<<dp[(i+1)%2][j-1]<<' '<<min(dp[(i+1)%2][j],dp[(i+1)%2][j-1])<<'\n';
        }
//        cout<<'\n';
	}
	cout<<dp[n%2][m];
	return 0;

}
